use_item_in_battle.python_script:
import json

def execute(input_data):
    current = int(input_data['current_item_index'])
    target = int(input_data['target_item_index'])
    start = input_data.get('start_on_main', True)
    presses = []
    if start:
        presses.extend(['Down', 'A', 'sleep 500'])
    diff = target - current
    if diff > 0:
        for _ in range(diff):
            presses.extend(['Down', 'sleep 100'])
    elif diff < 0:
        for _ in range(abs(diff)):
            presses.extend(['Up', 'sleep 100'])
    presses.extend(['A', 'sleep 500'])
    print(json.dumps(presses))

execute(input_data)
